import Lightdash from '@lightdash/sdk';

const INSTANCE_URL = 'http://localhost:3030';

// Generated by: node --import tsx test-sdk-embed/generate-embed-token.ts
// Regenerate after db reset or when token expires (24h)
const EMBED_TOKEN = import.meta.env.VITE_EMBED_TOKEN || '';

export default function App() {
    if (!EMBED_TOKEN) {
        return (
            <div style={{ padding: 20, fontFamily: 'system-ui' }}>
                <h1>Lightdash SDK Test</h1>
                <p>No embed token configured. Generate one:</p>
                <pre
                    style={{
                        background: '#f5f5f5',
                        padding: 16,
                        borderRadius: 8,
                    }}
                >
                    {`cd ${window.location.origin.replace('http://localhost:3030', '$(pwd)')}\nPGHOST=localhost node --import tsx test-sdk-embed/generate-embed-token.ts`}
                </pre>
                <p>
                    Then set <code>VITE_EMBED_TOKEN</code> in{' '}
                    <code>test-sdk-embed/.env.local</code> and restart.
                </p>
            </div>
        );
    }

    return (
        <div style={{ padding: 20, fontFamily: 'system-ui' }}>
            <h1>Lightdash SDK Embed Test</h1>
            <div style={{ width: '100%', height: '80vh' }}>
                <Lightdash.Dashboard
                    instanceUrl={INSTANCE_URL}
                    token={EMBED_TOKEN}
                />
            </div>
        </div>
    );
}
